                </div>
              )}

              <div className="mt-12 text-center md:hidden">
                <button className="inline-flex items-center text-blue-900 font-bold hover:text-blue-700 transition-colors">
                  Ver todas las propiedades <ArrowRight className="w-5 h-5 ml-2" />
